static void setWindowSize(SDL_VideoDevice *_this, SDL_Window *window)
{
    SDL_WindowData   *impl = (SDL_WindowData *)window->internal;
    int             size[2];

    size[0] = window->pending.w;
    size[1] = window->pending.h;

    if (!(window->flags & (SDL_WINDOW_FULLSCREEN | SDL_WINDOW_MAXIMIZED))) {
        if (screen_destroy_window_buffers(impl->window) < 0) {
            return;
        }
        impl->resize = 1;

        screen_set_window_property_iv(impl->window, SCREEN_PROPERTY_SIZE, size);
        screen_set_window_property_iv(impl->window, SCREEN_PROPERTY_SOURCE_SIZE, size);

        screen_create_window_buffers(impl->window, (window->flags & SDL_WINDOW_OPENGL) ? 2 : 1);
    } else {
        window->last_size_pending = false;
    }
}

bool SDL_SYS_CreateDirectory(const char *path)
{
    WCHAR *wpath = WIN_UTF8ToStringW(path);
    if (!wpath) {
        return false;
    }

    DWORD rc = CreateDirectoryW(wpath, NULL);
    if (!rc && (GetLastError() == ERROR_ALREADY_EXISTS)) {
        WIN32_FILE_ATTRIBUTE_DATA winstat;
        if (GetFileAttributesExW(wpath, GetFileExInfoStandard, &winstat)) {
            if (winstat.dwFileAttributes & FILE_ATTRIBUTE_DIRECTORY) {
                rc = 1;  // exists and is already a directory: cool.
            }
        }
    }

    SDL_free(wpath);
    if (!rc) {
        return WIN_SetError("Couldn't create directory");
    }
    return true;
}

static void SDL_EMSCRIPTEN_SensorUpdate(SDL_Sensor *sensor)
{
    Uint64 timestamp;

    switch (sensor->type) {
    case SDL_SENSOR_ACCEL:
        if (SDL_sensors[0].new_data) {
            SDL_sensors[0].new_data = false;
            timestamp = SDL_GetTicksNS();
            SDL_SendSensorUpdate(timestamp, sensor, timestamp, SDL_sensors[0].data, SDL_arraysize(SDL_sensors[0].data));
        }
        break;
    case SDL_SENSOR_GYRO:
        if (SDL_sensors[1].new_data) {
            SDL_sensors[1].new_data = false;
            timestamp = SDL_GetTicksNS();
            SDL_SendSensorUpdate(timestamp, sensor, timestamp, SDL_sensors[1].data, SDL_arraysize(SDL_sensors[1].data));
        }
        break;
    default:
        break;
    }
}

ngx_int_t
ngx_os_signal_process(ngx_cycle_t *cycle, char *sig, ngx_pid_t pid)
{
    HANDLE     ev;
    ngx_int_t  rc;
    char       evn[NGX_PROCESS_SYNC_NAME];

    ngx_sprintf((u_char *) evn, "Global\\ngx_%s_%P%Z", sig, pid);

    ev = OpenEvent(EVENT_MODIFY_STATE, 0, evn);
    if (ev == NULL) {
        ngx_log_error(NGX_LOG_ERR, cycle->log, ngx_errno,
                      "OpenEvent(\"%s\") failed", evn);
        return 1;
    }

    if (SetEvent(ev) == 0) {
        ngx_log_error(NGX_LOG_ALERT, cycle->log, ngx_errno,
                      "SetEvent(\"%s\") failed", evn);
        rc = 1;

    } else {
        rc = 0;
    }

    ngx_close_handle(ev);

    return rc;
}

